#include <bits/stdc++.h>
using namespace std;
const int maxn=3e3+5;
int n,xx;
double x[maxn],y[maxn],xs,minn=INT_MAX;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>x[i]>>y[i];
	}
	cin>>xs;
	for(int i=1; i<=n; i++) {
		double lx=x[i],ly=y[i],rx=x[i%n+1],ry=y[i%n+1];
		if((lx<=xs&&xs<=rx)) {
			double yy=(rx-xs)/(rx-lx)*(ly-ry)+ry;
			if(yy<minn) {
				minn=yy,xx=i;
			}
		} else if(rx<=xs&&xs<=lx) {
			double yy=(xs-lx)/(rx-lx)*(ry-ly)+ry;
			if(yy<minn) {
				minn=yy,xx=i;
			}
		}
	}
	cout<<xx<<" "<<xx%n+1;
	return 0;
}
